import React, { useState } from 'react';

function Deposit({ accounts, setAccounts }) {
  const [selectedId, setSelectedId] = useState('');
  const [amount, setAmount] = useState('');

  const handleDeposit = () => {
    const accIndex = accounts.findIndex(acc => acc.id === Number(selectedId));
    if (accIndex === -1 || amount <= 0) {
      alert("Invalid account or amount!");
      return;
    }

    const updatedAccounts = [...accounts];
    updatedAccounts[accIndex].balance += Number(amount);
    updatedAccounts[accIndex].transactions.push({ type: 'Deposit', amount: Number(amount) });
    setAccounts(updatedAccounts);
    alert("Deposit successful!");
    setAmount('');
  };

  return (
    <div className="form-container">
      <h2>Deposit Money</h2>
      <select value={selectedId} onChange={(e) => setSelectedId(e.target.value)}>
        <option value="">Select Account</option>
        {accounts.map(acc => (
          <option key={acc.id} value={acc.id}>{acc.name}</option>
        ))}
      </select>
      <input 
        type="number" 
        placeholder="Amount" 
        value={amount} 
        onChange={(e) => setAmount(e.target.value)} 
      />
      <button onClick={handleDeposit}>Deposit</button>
    </div>
  );
}

export default Deposit;
